{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Location { get; set; } = string.Empty;
    public DateTime LastInspected { get; set; }
}

public class EquipmentService
{
    private static readonly List<EquipmentItem> Items =
    [
        new() { Id = 1, Name = "Forklift A",       Location = "Warehouse 1", LastInspected = new(2026, 3, 12) },
        new() { Id = 2, Name = "Conveyor Belt B",  Location = "Warehouse 2", LastInspected = new(2026, 4, 1)  },
        new() { Id = 3, Name = "Drill Press C",    Location = "Shop Floor",  LastInspected = new(2026, 1, 20) },
        new() { Id = 4, Name = "Welding Station D",Location = "Shop Floor",  LastInspected = new(2025, 11, 5) },
        new() { Id = 5, Name = "CNC Router E",     Location = "Shop Floor",  LastInspected = new(2026, 5, 10) },
        new() { Id = 6, Name = "Pallet Jack F",    Location = "Warehouse 1", LastInspected = new(2026, 2, 28) },
        new() { Id = 7, Name = "Air Compressor G", Location = "Utility Room",LastInspected = new(2025, 12, 15)},
        new() { Id = 8, Name = "Generator H",      Location = "Utility Room",LastInspected = new(2026, 4, 22) },
    ];

    public async Task<List<EquipmentItem>> GetEquipmentAsync()
    {
        // Simulate async data access
        await Task.Delay(250);
        return Items;
    }
}

@page "/inventory"
@rendermode InteractiveServer
@inject InventoryApp.Services.EquipmentService EquipmentService

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (Items is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in Items)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [PersistentState]
    public List<InventoryApp.Services.EquipmentItem>? Items { get; set; }

    protected override async Task OnInitializedAsync()
    {
        // ??= ensures the service is called only once:
        // during prerender the data is fetched and serialized into the page;
        // when the interactive runtime attaches, the property is restored
        // from that serialized state so the fetch is skipped.
        Items ??= await EquipmentService.GetEquipmentAsync();
    }
}

